// Shared settings cache and save logic for persistent state
const settingsCache = { current: null, loaded: false, listeners: new Set() };

function loadSettings() {
  if (settingsCache.loaded) return Promise.resolve(settingsCache.current);
  return fetch('/api/settings')
    .then(r => r.ok ? r.json() : {})
    .then(data => { settingsCache.current = data; settingsCache.loaded = true; return data; })
    .catch(() => { settingsCache.current = {}; settingsCache.loaded = true; return {}; });
}

let saveTimer = null;
function saveSettings(allSettings) {
  settingsCache.current = { ...settingsCache.current, ...allSettings };
  clearTimeout(saveTimer);
  saveTimer = setTimeout(() => {
    fetch('/api/settings', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(settingsCache.current)
    }).catch(() => {});
  }, 500);
}

// Custom hook for API-backed persistent state
function usePersistentState(key, initialValue) {
  const [value, setValueRaw] = useState(initialValue);

  useEffect(() => {
    loadSettings().then(data => {
      if (data[key] !== undefined) setValueRaw(data[key]);
    });
  }, [key]);

  const setValue = useCallback((updater) => {
    setValueRaw(prev => {
      const next = updater instanceof Function ? updater(prev) : updater;
      saveSettings({ [key]: next });
      return next;
    });
  }, [key]);

  return [value, setValue];
}

