function normalizeOrgInput(orgRaw) {
  let organization = String(orgRaw || '').trim();
  if (!organization) return '';

  if (organization.includes('://')) {
    try {
      const parsed = new URL(organization);
      if (parsed.hostname === 'dev.azure.com') {
        organization = parsed.pathname.split('/').filter(Boolean)[0] || '';
      } else if (parsed.hostname.endsWith('.visualstudio.com')) {
        organization = parsed.hostname.split('.')[0] || '';
      }
    } catch (_) {
      // keep original
    }
  }
  return organization.trim();
}

function adoBaseUrl(org, project) {
  return `https://dev.azure.com/${encodeURIComponent(org)}/${encodeURIComponent(project)}/_apis`;
}

function adoHeaders(pat) {
  const auth = Buffer.from(`:${pat}`).toString('base64');
  return {
    Authorization: `Basic ${auth}`,
    Accept: 'application/json',
    // KEY: avoid redirecting to interactive AAD sign-in (HTML)
    'X-TFS-FedAuthRedirect': 'Suppress',
    // Optional but helpful
    'User-Agent': 'DevOpsDashboard/1.0'
  };
}

async function readTextSafe(resp) {
  try { return await resp.text(); } catch { return ''; }
}

function isLikelyHtml(ct, body) {
  const c = (ct || '').toLowerCase();
  const b = (body || '').trim().toLowerCase();
  return c.includes('text/html') || b.startsWith('<!doctype html') || b.startsWith('<html');
}

